import { useState } from 'react';
import { Maximize2, Minimize2 } from 'lucide-react';

const Card = ({ title, children, startOpen = true }) => {
  const [isOpen, setIsOpen] = useState(startOpen);

  return (
    <div className={`bg-black/40 p-4 rounded-lg shadow-lg transition-all duration-300 ${isOpen ? 'h-auto' : 'h-16 overflow-hidden'}`}>
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-xl font-bold text-mictlan-gold">{title}</h2>
        <div className="flex items-center space-x-2">
          <button
            onClick={(e) => {
              e.stopPropagation();
              setIsOpen(!isOpen);
            }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
          >
            {!isOpen ? <Maximize2 size={14} /> : <Minimize2 size={14} />}
          </button>
        </div>
      </div>
      {children}
    </div>
  );
};

export default Card;

