import { useState } from 'react';
import { Settings, RefreshCw, Trash2 } from 'lucide-react';
import { resetDatabase, emptyDatabase } from '../firebase/dbActions';

export default function AdminPanel() {
  const [tableCount, setTableCount] = useState(4);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isEmptying, setIsEmptying] = useState(false);

  const handleReset = async () => {
    setIsUpdating(true);
    try {
      await resetDatabase(tableCount);
    } catch {
      alert("Erreur lors de la mise à jour");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleEmpty = async () => {
    if (!confirm("Êtes-vous sûr de vouloir vider complètement la base de données ? Cette action est irréversible.")) {
      return;
    }
    setIsEmptying(true);
    try {
      await emptyDatabase();
      alert("Base de données vidée avec succès.");
    } catch {
      alert("Erreur lors du vidage de la base de données");
    } finally {
      setIsEmptying(false);
    }
  };

  return (
    <div className="bg-mictlan-dark-gray/50 border border-red-900/30 rounded-xl p-4 mt-10">
      <h3 className="text-mictlan-gold text-[10px] font-black uppercase tracking-[0.2em] mb-4 flex items-center">
        <Settings className="w-3 h-3 mr-2" /> Configuration Système
      </h3>
      
      <div className="flex items-end gap-4">
        <div className="flex-1">
          <label className="block text-gray-500 text-[9px] uppercase mb-1">Nombre de tables en salle</label>
          <input 
            type="number" 
            value={tableCount}
            onChange={(e) => setTableCount(e.target.value)}
            className="w-full bg-black border border-gray-800 rounded p-2 text-white outline-none focus:border-mictlan-gold"
            min="1"
            max="50"
          />
        </div>
        
        <button 
          onClick={handleReset}
          disabled={isUpdating}
          className="bg-red-900/20 hover:bg-red-600 text-red-500 hover:text-white border border-red-900 px-4 py-2 rounded font-bold text-[10px] uppercase transition-all flex items-center gap-2"
        >
          <RefreshCw className={`w-3 h-3 ${isUpdating ? 'animate-spin' : ''}`} />
          {isUpdating ? 'Mise à jour...' : 'Réinitialiser Salle'}
        </button>
        <button 
          onClick={handleEmpty}
          disabled={isEmptying}
          className="bg-red-900/20 hover:bg-600 text-red-500 hover:text-white border border-red-900 px-4 py-2 rounded font-bold text-[10px] uppercase transition-all flex items-center gap-2"
        >
          <Trash2 className={`w-3 h-3 ${isEmptying ? 'animate-spin' : ''}`} />
          {isEmptying ? 'Vidage...' : 'Vider DB'}
        </button>
      </div>
      <p className="text-[8px] text-gray-600 mt-2 italic font-mono uppercase">
        * Réinitialiser Salle : Efface toutes les données actuelles pour générer {tableCount} tables. Vider DB : Supprime toutes les données des collections connues (tables, inventory, logs, users). Pour vider toutes les collections inconnues, exécutez `npm run empty-db` or `node empty-db.cjs` dans un terminal.
      </p>
    </div>
  );
}

import { useState } from 'react';
import { Package, Maximize2, Minimize2, ChevronDown, ChevronUp, AlertTriangle, CheckCircle, XCircle } from 'lucide-react';
import { useInventory } from '../hooks/useInventory';
import { useLogs } from '../hooks/useLogs';

export default function Inventory({ user }) {
  const [isOpen, setIsOpen] = useState(true);
  const { inventory, updateStatus } = useInventory();
  const { addLog } = useLogs();

  const getStatusColor = (status) => {
    switch (status) {
      case 'ok': return 'text-green-500';
      case 'low': return 'text-orange-500';
      case 'out': return 'text-red-600 animate-pulse';
      default: return 'text-gray-500';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'ok': return <CheckCircle size={16} className="text-green-500" />;
      case 'low': return <AlertTriangle size={16} className="text-orange-500" />;
      case 'out': return <XCircle size={16} className="text-red-600" />;
      default: return <Package size={16} className="text-gray-500" />;
    }
  };

  const handleStatusClick = async (item) => {
    const statusCycle = { ok: 'low', low: 'out', out: 'ok' };
    const nextStatus = statusCycle[item.status] || 'ok';
    await updateStatus(item.id, nextStatus, item.name, addLog, user);
  };

  return (
    <div className="bg-mictlan-dark-gray/30 rounded-3xl border border-gray-800 overflow-hidden transition-all duration-300 shadow-lg">
      <div
        className="flex justify-between items-center p-6 cursor-pointer hover:bg-white/5 transition-colors"
        onClick={() => setIsOpen(!isOpen)}
      >
        <h2 className="text-sm font-black text-mictlan-gold uppercase tracking-[0.3em] flex items-center">
          <Package className="mr-2 w-4 h-4" /> Inventaire
        </h2>

        <div className="flex items-center gap-3">
          <button
            onClick={(e) => {
              e.stopPropagation();
              setIsOpen(!isOpen);
            }}
            className="p-1.5 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all"
            title={!isOpen ? "Expand All" : "Collapse All"}
          >
            {!isOpen ? <Maximize2 size={14}/> : <Minimize2 size={14}/>}
          </button>

          <div className="text-gray-500">
            {isOpen ? <ChevronUp size={18} /> : <ChevronDown size={18} className="text-mictlan-gold" />}
          </div>
        </div>
      </div>

      {isOpen && (
        <div className="px-6 pb-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
            {inventory.map((item) => (
              <div
                key={item.id}
                onClick={() => handleStatusClick(item)}
                className="bg-black/30 p-3 rounded-lg border border-gray-800 hover:border-mictlan-gold/50 cursor-pointer transition-all group"
              >
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs font-medium text-gray-300 uppercase tracking-wide">
                    {item.name}
                  </span>
                  {getStatusIcon(item.status)}
                </div>
                <div className={`text-xs font-bold ${getStatusColor(item.status)}`}>
                  {item.status === 'ok' ? 'EN STOCK' :
                   item.status === 'low' ? 'STOCK FAIBLE' :
                   item.status === 'out' ? 'ÉPUISÉ' : 'INCONNU'}
                </div>
                {item.quantity && (
                  <div className="text-[10px] text-gray-500 mt-1">
                    Qté: {item.quantity}
                  </div>
                )}
              </div>
            ))}
          </div>

          {inventory.length === 0 && (
            <div className="text-center py-8 text-gray-500">
              <Package size={48} className="mx-auto mb-4 opacity-50" />
              <p className="text-sm">Aucun article en inventaire</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

